{
  "cleanupPeriodDays": 1095,
  "env": {
    "CLAUDE_CODE_ENABLE_TELEMETRY": "1",
    "OTEL_EXPORTER_OTLP_ENDPOINT": "http://127.0.0.1:4317",
    "OTEL_EXPORTER_OTLP_PROTOCOL": "grpc",
    "OTEL_LOGS_EXPORTER": "otlp",
    "OTEL_LOG_USER_PROMPTS": "1",
    "OTEL_METRICS_EXPORTER": "otlp"
  },
  "permissions": {
    "allow": [
      "Bash(deepline *)",
      "Bash(export PATH=$HOME/.local/bin:$PATH && deepline *)"
    ],
    "deny": [
      "TaskCreate",
      "TaskGet",
      "TaskList",
      "TaskOutput",
      "TaskStop",
      "TaskUpdate"
    ],
    "defaultMode": "auto"
  },
  "model": "opus[1m]",
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "jq -r '.tool_input.file_path' | { read -r filepath; if [[ \"$filepath\" =~ design/(plans|specs) ]]; then filename=$(basename \"$filepath\"); if ! [[ \"$filename\" =~ ^(done|backlog|in_progress|waiting|deployed|archived|paused)_ ]]; then echo '{\"continue\": false, \"stopReason\": \"Status prefix required: File in design artifacts must start with status prefix (done_, backlog_, in_progress_, waiting_, deployed_, archived_, paused_). Example: backlog_2026-03-29-my-plan.md\"}'; exit 1; fi; fi; echo '{}'; }",
            "statusMessage": "Validating artifact status prefix..."
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "$HOME/.claude/hooks/block-push-protected.sh",
            "statusMessage": "Checking git push branch policy..."
          }
        ]
      }
    ],
    "WorktreeCreate": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "input=$(cat); name=$(echo \"$input\" | jq -r '.name // empty'); name=${name:-$(openssl rand -hex 4)}; branch=\"worktree-$name\"; root=$(git rev-parse --show-toplevel); dir=\"$root/worktrees/$name\"; if [ -d \"$dir\" ]; then existing_branch=$(git -C \"$dir\" rev-parse --abbrev-ref HEAD); echo \"{\\\"worktreePath\\\": \\\"$dir\\\", \\\"branch\\\": \\\"$existing_branch\\\"}\"; else mkdir -p \"$root/worktrees\" && git worktree add \"$dir\" -b \"$branch\" && echo \"{\\\"worktreePath\\\": \\\"$dir\\\", \\\"branch\\\": \\\"$branch\\\"}\"; fi",
            "timeout": 30000
          }
        ]
      }
    ],
    "WorktreeRemove": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "input=$(cat); path=$(echo \"$input\" | jq -r '.worktreePath // empty'); branch=$(echo \"$input\" | jq -r '.branch // empty'); [ -n \"$path\" ] && git worktree remove \"$path\" 2>/dev/null; [ -n \"$branch\" ] && git branch -D \"$branch\" 2>/dev/null; echo '{}'",
            "timeout": 30000
          }
        ]
      }
    ]
  },
  "enabledPlugins": {
    "agent-sdk-dev@claude-plugins-official": false,
    "circleback@claude-plugins-official": false,
    "claude-code-setup@claude-plugins-official": false,
    "claude-md-management@claude-plugins-official": false,
    "code-review@claude-plugins-official": false,
    "code-simplifier@claude-plugins-official": false,
    "coderabbit@claude-plugins-official": false,

